// Repackage n8n's error-trigger payload into Laya's /ingestion-errors schema.
// Runs once per failed execution of any workflow that has this handler wired
// via settings.errorWorkflow. Does NOT resolve source_id / space_id — the
// engine does that server-side from workflow_id.

// Order matters: "outlook calendar" must be checked before "outlook".
const PLATFORM_RULES = [
  ['google calendar', 'calendar'],
  ['outlook calendar', 'outlook_calendar'],
  ['outlook', 'outlook'],
  ['gmail', 'gmail'],
  ['slack', 'slack'],
  ['jira', 'jira'],
  ['bitbucket', 'bitbucket'],
  ['github', 'github'],
  ['linear', 'linear'],
  ['notion', 'notion']
];

function derivePlatform(name) {
  const lower = (name || '').toLowerCase();
  for (const [needle, platform] of PLATFORM_RULES) {
    if (lower.includes(needle)) return platform;
  }
  return 'unknown';
}

// Cheap deterministic hash of a string → 8 hex chars. Used to build a stable
// idempotency key so an n8n retry of the error-handler POST doesn't create a
// duplicate row. Server-side fingerprint is the source of truth for dedup.
function shortHash(str) {
  let h = 0;
  const s = str || '';
  for (let i = 0; i < s.length; i++) {
    h = ((h << 5) - h) + s.charCodeAt(i);
    h |= 0;
  }
  return (h >>> 0).toString(16).padStart(8, '0');
}

const input = $input.first() ? $input.first().json : {};
const exec = input.execution || {};
const wf = input.workflow || {};
const err = exec.error || {};
const nodeName = exec.lastNodeExecuted || '';
const node = (wf.nodes || []).find(n => n.name === nodeName) || {};

const executionId = String(exec.id || '');
const errorId = executionId
  ? `ierr_${executionId}_${shortHash(nodeName)}`
  : `ierr_${Date.now()}_${shortHash(nodeName)}`;

const httpCode = err.httpCode !== undefined && err.httpCode !== null && err.httpCode !== ''
  ? Number(err.httpCode)
  : null;

return [{
  json: {
    error_id: errorId,
    workflow_id: wf.id || '',
    workflow_name: wf.name || '',
    platform: derivePlatform(wf.name),
    execution_id: executionId,
    execution_url: exec.url || '',
    execution_mode: exec.mode || '',
    node_name: nodeName,
    node_type: node.type || '',
    error_name: err.name || '',
    error_message: err.message || 'Unknown error',
    error_http_code: Number.isFinite(httpCode) ? httpCode : null,
    error_stack: err.stack || '',
    error_details: err,
    occurred_at: new Date().toISOString()
  }
}];
